function deepClone(obj){ return JSON.parse(JSON.stringify(obj)); }

async function loadState(){
  try{
    const result = await window.storage.get(STORAGE_KEY, true);
    if(result && result.value){
      STATE = JSON.parse(result.value);
      migrateOkp();
      return;
    }
  }catch(e){}
  STATE = deepClone(SEED_DATA);
  migrateOkp();
  await saveState();
}

// Приводит структуру ОКП к текущему списку дисциплин и специалистов.
// Даты и откаты сохраняются; старый раздел «ОВ/ВК/Эл» переносится на Электрику и ВК.
function migrateOkp(){
  if(!STATE.okp) STATE.okp = {reviewers:{}, reviews:{}};
  // Канонический ростер специалистов
  STATE.okp.reviewers = JSON.parse(JSON.stringify(OKP_REVIEWERS));
  if(!STATE.okp.reviews) STATE.okp.reviews = {};

  Object.keys(STATE.okp.reviews).forEach(pid=>{
    const rv = STATE.okp.reviews[pid] || {};
    // Перенос старого объединённого раздела ОВ/ВК/Эл -> Электрика + ВК
    if(rv.ovvkel){
      const src = rv.ovvkel;
      ['el','vk'].forEach(k=>{
        if(!rv[k]) rv[k] = {reviewer:'', load:src.load||'', issue:src.issue||'', rbStart:src.rbStart||'', rbEnd:src.rbEnd||''};
      });
      delete rv.ovvkel;
    }
    // Гарантируем наличие всех текущих разделов
    SECTION_ORDER.forEach(k=>{
      if(!rv[k]) rv[k] = {reviewer:'', load:'', issue:'', rbStart:'', rbEnd:''};
      // Если сохранённый исполнитель больше не в списке — очищаем (даты остаются)
      const opts = STATE.okp.reviewers[k] || [];
      if(rv[k].reviewer && !opts.includes(rv[k].reviewer)) rv[k].reviewer = '';
    });
    STATE.okp.reviews[pid] = rv;
  });
}

async function saveState(){
  try{
    await window.storage.set(STORAGE_KEY, JSON.stringify(STATE), true);
  }catch(e){
    console.error('Save failed', e);
    showToast('Ошибка сохранения данных');
  }
}

function showToast(msg){
  let t = document.getElementById('toast');
  if(!t){
    t = document.createElement('div');
    t.id = 'toast';
    t.className = 'toast';
    document.body.appendChild(t);
  }
  t.textContent = msg;
  t.classList.add('show');
  clearTimeout(window._toastTimer);
  window._toastTimer = setTimeout(()=>{ t.classList.remove('show'); }, 2200);
}

function parseDate(s){
  if(!s) return null;
  const d = new Date(s + 'T00:00:00');
  return isNaN(d.getTime()) ? null : d;
}

function daysBetween(s, e){
  const d1 = parseDate(s), d2 = parseDate(e);
  if(!d1 || !d2) return null;
  return Math.round((d2 - d1) / 86400000);
}

function fmtDate(s){
  const d = parseDate(s);
  if(!d) return '—';
  return d.toLocaleDateString('ru-RU', {day:'2-digit', month:'2-digit', year:'2-digit'});
}

function projectDuration(p){
  const dates = [];
  p.stages.forEach(st=>{
    if(st.start) dates.push(parseDate(st.start));
    if(st.end) dates.push(parseDate(st.end));
  });
  if(dates.length === 0) return null;
  const min = new Date(Math.min(...dates));
  const max = new Date(Math.max(...dates));
  return {start: min, end: max, days: Math.round((max-min)/86400000)};
}

function stageProgress(st){
  if(st.na) return {pct: null, cls: 's-na', label: 'н/д'};
  if(typeof st.pct === 'number') {
    if(st.pct >= 100) return {pct: st.pct, cls: 's-done', label: st.pct + '%'};
    if(st.pct > 0) return {pct: st.pct, cls: 's-progress', label: st.pct + '%'};
    return {pct: 0, cls: 's-pending', label: '0%'};
  }
  if(st.start && st.end) return {pct: 100, cls: 's-done', label: '100%'};
  if(st.start) return {pct: 50, cls: 's-progress', label: 'идёт'};
  return {pct: 0, cls: 's-pending', label: '0%'};
}

function projectOverallPct(p){
  const vals = p.stages.map(st=>{
    if(st.na) return null;
    if(typeof st.pct === 'number') return st.pct;
    if(st.start && st.end) return 100;
    if(st.start) return 50;
    return 0;
  }).filter(v=>v !== null);
  if(vals.length === 0) return 0;
  return Math.round(vals.reduce((a,b)=>a+b,0) / vals.length);
}

function projectStatusInfo(p){
  const pct = projectOverallPct(p);
  if(pct >= 100) return {pct, cls:'status-done', label: pct + '% · Завершён'};
  if(pct === 0) return {pct, cls:'status-progress', label: '0% · Не начат'};
  return {pct, cls:'status-progress', label: pct + '% · В работе'};
}

