function sverkaSeverity(pct){
  if(pct >= 70) return {cls:'high', tag:'Высокая'};
  if(pct > 0) return {cls:'mid', tag:'Средняя'};
  return {cls:'zero', tag:'Не начато'};
}

function renderSverkaProject(projId, data){
  const total = Math.round(data.rows.reduce((a,r)=>a+r.pct,0) / data.rows.length);
  let rows = '';
  data.rows.forEach(r=>{
    const sev = sverkaSeverity(r.pct);
    rows += `
    <div class="collision-row ${sev.cls}">
      <div><div class="task-name">${r.section}</div><div class="task-who">${r.who||''}</div></div>
      <div class="change-badge"><div class="change-bar-track"><div class="change-bar-fill ${sev.cls}" style="width:${Math.max(r.pct,2)}%"></div></div><div class="change-pct">${r.pct}%</div></div>
      <div><span class="severity-tag ${sev.cls}">${sev.tag}</span></div>
      <div class="comment-text ${r.comment?'':'empty'}">${r.comment || 'Комментариев нет — раздел в работу не взят.'}</div>
    </div>`;
  });
  return `
  <div class="project-block">
    <div class="project-banner"><div class="name">${data.projectName}</div><div class="total"><span class="tlabel">Общий объём изменений</span><span class="tval mono">${total}%</span></div></div>
    <div class="collision-table">
      <div class="col-header"><div>Раздел</div><div>% изменений</div><div>Уровень</div><div>Что изменено</div></div>
      ${rows}
    </div>
  </div>`;
}

